import {
  createRouter,
  createRootRoute,
  createRoute,
  createHashHistory,
} from '@tanstack/react-router'
import { z } from 'zod'
import { RootComponent } from './components/RootComponent'
import { ShopPage } from './pages/ShopPage'

// ── Cart search-param schema ──────────────────────────────────────────────────
// cart is encoded as a JSON string in the URL: ?cart=[{"id":1,"qty":2},...]
const cartItemSchema = z.object({
  id: z.number(),
  qty: z.number().int().positive(),
})

export type CartItem = z.infer<typeof cartItemSchema>

const searchSchema = z.object({
  cart: z.array(cartItemSchema).optional().default([]),
  category: z.string().optional().default('All'),
})

export type ShopSearch = z.infer<typeof searchSchema>

// ── Routes ────────────────────────────────────────────────────────────────────
const rootRoute = createRootRoute({
  component: RootComponent,
})

export const shopRoute = createRoute({
  getParentRoute: () => rootRoute,
  path: '/',
  component: ShopPage,
  validateSearch: (raw: Record<string, unknown>): ShopSearch => {
    return searchSchema.parse(raw)
  },
})

const routeTree = rootRoute.addChildren([shopRoute])

export const router = createRouter({
  routeTree,
  history: createHashHistory(),
  defaultPreload: 'intent',
})

declare module '@tanstack/react-router' {
  interface Register {
    router: typeof router
  }
}

import { Outlet } from '@tanstack/react-router'

export function RootComponent() {
  return <Outlet />
}

import { useNavigate, useSearch } from '@tanstack/react-router'
import { shopRoute, type CartItem } from '../router'

export function useCart() {
  const { cart } = useSearch({ from: shopRoute.id })
  const navigate = useNavigate({ from: shopRoute.id })

  function updateCart(updater: (prev: CartItem[]) => CartItem[]) {
    navigate({
      search: (prev) => ({
        ...prev,
        cart: updater(prev.cart ?? []),
      }),
      replace: true,
    })
  }

  function addItem(productId: number) {
    updateCart((prev) => {
      const existing = prev.find((i) => i.id === productId)
      if (existing) {
        return prev.map((i) =>
          i.id === productId ? { ...i, qty: i.qty + 1 } : i
        )
      }
      return [...prev, { id: productId, qty: 1 }]
    })
  }

  function removeItem(productId: number) {
    updateCart((prev) => prev.filter((i) => i.id !== productId))
  }

  function setQuantity(productId: number, qty: number) {
    if (qty <= 0) {
      removeItem(productId)
      return
    }
    updateCart((prev) =>
      prev.map((i) => (i.id === productId ? { ...i, qty } : i))
    )
  }

  function clearCart() {
    updateCart(() => [])
  }

  const totalItems = cart.reduce((sum, i) => sum + i.qty, 0)

  return { cart, addItem, removeItem, setQuantity, clearCart, totalItems }
}

import { useNavigate, useSearch } from '@tanstack/react-router'
import { shopRoute } from '../router'
import type { Product } from '../data/products'

interface CategoryFilterProps {
  products: Product[]
}

export function CategoryFilter({ products }: CategoryFilterProps) {
  const { category } = useSearch({ from: shopRoute.id })
  const navigate = useNavigate({ from: shopRoute.id })

  const categories = ['All', ...Array.from(new Set(products.map((p) => p.category))).sort()]

  function setCategory(cat: string) {
    navigate({
      search: (prev) => ({ ...prev, category: cat }),
      replace: true,
    })
  }

  return (
    <div className="category-filter">
      {categories.map((cat) => (
        <button
          key={cat}
          className={`category-btn ${category === cat ? 'active' : ''}`}
          onClick={() => setCategory(cat)}
        >
          {cat}
        </button>
      ))}
    </div>
  )
}

import { useQuery } from '@tanstack/react-query'
import { useSearch } from '@tanstack/react-router'
import { fetchProducts } from '../data/products'
import { ProductCard } from '../components/ProductCard'
import { CartSidebar } from '../components/CartSidebar'
import { CategoryFilter } from '../components/CategoryFilter'
import { shopRoute } from '../router'

export function ShopPage() {
  const { category } = useSearch({ from: shopRoute.id })

  const {
    data: products = [],
    isLoading,
    isError,
    error,
  } = useQuery({
    queryKey: ['products'],
    queryFn: fetchProducts,
    staleTime: 5 * 60 * 1000,
  })

  const filteredProducts =
    category === 'All' ? products : products.filter((p) => p.category === category)

  return (
    <div className="app-layout">
      {/* ── Header ── */}
      <header className="app-header">
        <div className="header-brand">
          <span className="header-logo">🛍️</span>
          <div>
            <h1 className="header-title">TanStack Shop</h1>
            <p className="header-sub">Powered by TanStack Query &amp; Router</p>
          </div>
        </div>
      </header>

      {/* ── Main content ── */}
      <div className="main-content">
        <div className="product-section">
          {/* Category bar */}
          {!isLoading && !isError && (
            <CategoryFilter products={products} />
          )}

          {/* Product grid */}
          {isLoading && (
            <div className="loading-state">
              <div className="spinner" />
              <p>Loading products…</p>
            </div>
          )}

          {isError && (
            <div className="error-state">
              <p>⚠️ Failed to load products: {(error as Error).message}</p>
            </div>
          )}

          {!isLoading && !isError && (
            <>
              <p className="product-count">
                Showing <strong>{filteredProducts.length}</strong> product
                {filteredProducts.length !== 1 ? 's' : ''}
                {category !== 'All' ? ` in "${category}"` : ''}
              </p>
              {filteredProducts.length === 0 ? (
                <div className="empty-category">
                  <p>No products found in this category.</p>
                </div>
              ) : (
                <div className="product-grid">
                  {filteredProducts.map((product) => (
                    <ProductCard key={product.id} product={product} />
                  ))}
                </div>
              )}
            </>
          )}
        </div>

        {/* Cart sidebar */}
        <CartSidebar />
      </div>
    </div>
  )
}

import { StrictMode } from 'react'
import { createRoot } from 'react-dom/client'
import { QueryClient, QueryClientProvider } from '@tanstack/react-query'
import { RouterProvider } from '@tanstack/react-router'
import { ReactQueryDevtools } from '@tanstack/react-query-devtools'
import { router } from './router'
import './styles/index.css'

const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      retry: 2,
      refetchOnWindowFocus: false,
    },
  },
})

createRoot(document.getElementById('root')!).render(
  <StrictMode>
    <QueryClientProvider client={queryClient}>
      <RouterProvider router={router} />
      <ReactQueryDevtools initialIsOpen={false} buttonPosition="bottom-left" />
    </QueryClientProvider>
  </StrictMode>,
)

