/* ── Reset & Base ─────────────────────────────────────────────────────────── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --brand:       #6366f1;
  --brand-dark:  #4f46e5;
  --brand-light: #e0e7ff;
  --accent:      #f59e0b;
  --success:     #10b981;
  --danger:      #ef4444;
  --bg:          #f8fafc;
  --surface:     #ffffff;
  --border:      #e2e8f0;
  --text:        #1e293b;
  --text-muted:  #64748b;
  --shadow-sm:   0 1px 3px rgba(0,0,0,.08);
  --shadow-md:   0 4px 12px rgba(0,0,0,.10);
  --shadow-lg:   0 8px 24px rgba(0,0,0,.12);
  --radius:      12px;
  --radius-sm:   8px;
  font-family: 'Inter', 'Segoe UI', system-ui, sans-serif;
}

body {
  background: var(--bg);
  color: var(--text);
  min-height: 100vh;
}

/* ── Layout ───────────────────────────────────────────────────────────────── */
.app-layout {
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}

.main-content {
  display: flex;
  flex: 1;
  gap: 0;
  max-width: 1440px;
  width: 100%;
  margin: 0 auto;
  padding: 24px 20px;
  gap: 24px;
  align-items: flex-start;
}

.product-section {
  flex: 1;
  min-width: 0;
}

/* ── Header ───────────────────────────────────────────────────────────────── */
.app-header {
  background: linear-gradient(135deg, var(--brand) 0%, var(--brand-dark) 100%);
  color: #fff;
  padding: 20px 32px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  box-shadow: var(--shadow-md);
}

.header-brand {
  display: flex;
  align-items: center;
  gap: 14px;
}

.header-logo { font-size: 2.2rem; }

.header-title {
  font-size: 1.6rem;
  font-weight: 700;
  letter-spacing: -0.5px;
}

.header-sub {
  font-size: 0.78rem;
  opacity: 0.75;
  margin-top: 2px;
}

/* ── Category Filter ──────────────────────────────────────────────────────── */
.category-filter {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  margin-bottom: 20px;
}

.category-btn {
  padding: 7px 16px;
  border-radius: 999px;
  border: 2px solid var(--border);
  background: var(--surface);
  color: var(--text-muted);
  font-size: 0.85rem;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.15s ease;
}

.category-btn:hover {
  border-color: var(--brand);
  color: var(--brand);
}

.category-btn.active {
  background: var(--brand);
  border-color: var(--brand);
  color: #fff;
  box-shadow: 0 2px 8px rgba(99,102,241,.35);
}

/* ── Product Count ────────────────────────────────────────────────────────── */
.product-count {
  color: var(--text-muted);
  font-size: 0.875rem;
  margin-bottom: 16px;
}

/* ── Product Grid ─────────────────────────────────────────────────────────── */
.product-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
  gap: 20px;
}

/* ── Product Card ─────────────────────────────────────────────────────────── */
.product-card {
  background: var(--surface);
  border: 2px solid var(--border);
  border-radius: var(--radius);
  padding: 20px;
  display: flex;
  flex-direction: column;
  gap: 10px;
  transition: transform 0.18s ease, box-shadow 0.18s ease, border-color 0.18s ease;
  position: relative;
  overflow: hidden;
}

.product-card:hover {
  transform: translateY(-3px);
  box-shadow: var(--shadow-lg);
}

.product-card.in-cart {
  border-color: var(--brand);
  background: linear-gradient(135deg, #fafbff 0%, #f0f3ff 100%);
}

.product-card.in-cart::before {
  content: '✓ In Cart';
  position: absolute;
  top: 12px;
  right: 12px;
  background: var(--brand);
  color: #fff;
  font-size: 0.7rem;
  font-weight: 600;
  padding: 3px 8px;
  border-radius: 999px;
}

.product-emoji {
  font-size: 3rem;
  text-align: center;
  line-height: 1;
  padding: 8px 0;
}

.product-badge {
  display: inline-block;
  background: var(--brand-light);
  color: var(--brand-dark);
  font-size: 0.7rem;
  font-weight: 600;
  padding: 3px 10px;
  border-radius: 999px;
  width: fit-content;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.product-name {
  font-size: 1rem;
  font-weight: 700;
  line-height: 1.35;
  color: var(--text);
}

.product-description {
  font-size: 0.82rem;
  color: var(--text-muted);
  line-height: 1.5;
  flex: 1;
}

.product-meta {
  display: flex;
  align-items: center;
  justify-content: space-between;
  font-size: 0.78rem;
}

.product-rating {
  color: var(--accent);
  display: flex;
  align-items: center;
  gap: 4px;
}

.rating-value {
  color: var(--text-muted);
  font-weight: 600;
}

.product-stock {
  color: var(--text-muted);
}

.product-footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-top: 4px;
  gap: 10px;
}

.product-price {
  font-size: 1.25rem;
  font-weight: 800;
  color: var(--brand-dark);
}

/* ── Buttons ──────────────────────────────────────────────────────────────── */
.add-btn {
  background: var(--brand);
  color: #fff;
  border: none;
  padding: 9px 18px;
  border-radius: var(--radius-sm);
  font-size: 0.85rem;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.15s ease, transform 0.1s ease;
  white-space: nowrap;
}

.add-btn:hover  { background: var(--brand-dark); }
.add-btn:active { transform: scale(0.97); }

.quantity-control {
  display: flex;
  align-items: center;
  gap: 6px;
}

.qty-btn {
  width: 30px;
  height: 30px;
  border-radius: 6px;
  border: 2px solid var(--brand);
  background: var(--surface);
  color: var(--brand);
  font-size: 1.1rem;
  font-weight: 700;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.12s ease;
  line-height: 1;
}

.qty-btn:hover { background: var(--brand); color: #fff; }

.qty-value {
  min-width: 28px;
  text-align: center;
  font-weight: 700;
  font-size: 1rem;
}

.remove-btn {
  background: none;
  border: none;
  cursor: pointer;
  font-size: 1rem;
  opacity: 0.6;
  transition: opacity 0.15s;
  padding: 4px;
}

.remove-btn:hover { opacity: 1; }

/* ── Cart Sidebar ─────────────────────────────────────────────────────────── */
.cart-sidebar {
  width: 360px;
  flex-shrink: 0;
  background: var(--surface);
  border: 2px solid var(--border);
  border-radius: var(--radius);
  padding: 20px;
  position: sticky;
  top: 24px;
  max-height: calc(100vh - 100px);
  overflow-y: auto;
  box-shadow: var(--shadow-md);
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.cart-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-bottom: 16px;
  border-bottom: 2px solid var(--border);
}

.cart-title {
  font-size: 1.1rem;
  font-weight: 700;
  display: flex;
  align-items: center;
  gap: 8px;
}

.cart-badge {
  background: var(--brand);
  color: #fff;
  font-size: 0.7rem;
  font-weight: 700;
  padding: 2px 7px;
  border-radius: 999px;
  min-width: 22px;
  text-align: center;
}

.clear-btn {
  background: none;
  border: 1px solid var(--danger);
  color: var(--danger);
  font-size: 0.78rem;
  padding: 4px 10px;
  border-radius: 6px;
  cursor: pointer;
  transition: all 0.15s;
}

.clear-btn:hover {
  background: var(--danger);
  color: #fff;
}

/* Empty cart */
.cart-empty {
  text-align: center;
  padding: 32px 0;
  color: var(--text-muted);
}

.cart-empty-icon { font-size: 3rem; margin-bottom: 12px; }

.cart-empty-sub {
  font-size: 0.82rem;
  margin-top: 6px;
  opacity: 0.7;
}

/* Cart items list */
.cart-items {
  list-style: none;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.cart-item {
  display: flex;
  align-items: flex-start;
  gap: 10px;
  padding-bottom: 12px;
  border-bottom: 1px solid var(--border);
}

.cart-item:last-child { border-bottom: none; }

.cart-item-emoji { font-size: 1.8rem; flex-shrink: 0; line-height: 1; }

.cart-item-info {
  flex: 1;
  min-width: 0;
}

.cart-item-name {
  font-size: 0.82rem;
  font-weight: 600;
  line-height: 1.4;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.cart-item-price {
  font-size: 0.76rem;
  color: var(--text-muted);
  margin-top: 2px;
}

.cart-item-controls {
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  gap: 4px;
  flex-shrink: 0;
}

.qty-row {
  display: flex;
  align-items: center;
  gap: 4px;
}

.qty-btn-sm {
  width: 24px;
  height: 24px;
  border-radius: 5px;
  border: 1.5px solid var(--border);
  background: var(--bg);
  color: var(--text);
  font-size: 0.95rem;
  font-weight: 700;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.12s;
  line-height: 1;
}

.qty-btn-sm:hover {
  border-color: var(--brand);
  color: var(--brand);
  background: var(--brand-light);
}

.qty-value-sm {
  min-width: 20px;
  text-align: center;
  font-size: 0.85rem;
  font-weight: 700;
}

.cart-item-subtotal {
  font-size: 0.82rem;
  font-weight: 700;
  color: var(--brand-dark);
}

.remove-btn-sm {
  background: none;
  border: none;
  color: var(--text-muted);
  font-size: 1.1rem;
  cursor: pointer;
  line-height: 1;
  transition: color 0.12s;
  padding: 0;
}

.remove-btn-sm:hover { color: var(--danger); }

/* Cart summary */
.cart-summary {
  border-top: 2px solid var(--border);
  padding-top: 16px;
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.summary-row {
  display: flex;
  justify-content: space-between;
  font-size: 0.88rem;
  color: var(--text-muted);
}

.free-shipping {
  color: var(--success);
  font-weight: 700;
  font-size: 0.82rem;
}

.summary-divider {
  height: 1px;
  background: var(--border);
}

.total-row {
  font-size: 1.05rem;
  font-weight: 700;
  color: var(--text);
}

.checkout-btn {
  width: 100%;
  padding: 13px;
  background: linear-gradient(135deg, var(--brand) 0%, var(--brand-dark) 100%);
  color: #fff;
  border: none;
  border-radius: var(--radius-sm);
  font-size: 0.95rem;
  font-weight: 700;
  cursor: pointer;
  transition: opacity 0.15s, transform 0.1s;
  box-shadow: 0 3px 10px rgba(99,102,241,.35);
}

.checkout-btn:hover  { opacity: 0.92; }
.checkout-btn:active { transform: scale(0.98); }

.url-hint {
  text-align: center;
  font-size: 0.72rem;
  color: var(--text-muted);
  line-height: 1.5;
  padding: 8px 12px;
  background: var(--bg);
  border-radius: var(--radius-sm);
  border: 1px dashed var(--border);
}

/* ── Loading / Error States ───────────────────────────────────────────────── */
.loading-state, .error-state, .empty-category {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 16px;
  padding: 80px 40px;
  color: var(--text-muted);
  text-align: center;
}

.spinner {
  width: 44px;
  height: 44px;
  border: 4px solid var(--border);
  border-top-color: var(--brand);
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

.error-state { color: var(--danger); }

/* ── Responsive ───────────────────────────────────────────────────────────── */
@media (max-width: 900px) {
  .main-content {
    flex-direction: column-reverse;
  }

  .cart-sidebar {
    width: 100%;
    position: static;
    max-height: none;
  }
}

@media (max-width: 480px) {
  .app-header { padding: 14px 16px; }
  .header-title { font-size: 1.2rem; }
  .product-grid { grid-template-columns: 1fr; }
}
